section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/cog-walk-basics.json",
  "title": "Cognitive Walkthrough: Basics",
  "type": "object",
  "required": [
    "artefact_id",
    "persona",
    "task",
    "correct_steps",
    "step_evaluations",
    "issues",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date",
      "minLength": 1
    },
    "persona": {
      "type": "object",
      "description": "first-time user with goal + skill profile"
    },
    "task": {
      "type": "string",
      "description": "single goal-directed task",
      "minLength": 1
    },
    "correct_steps": {
      "type": "array",
      "description": "ordered correct action sequence",
      "minItems": 1
    },
    "step_evaluations": {
      "type": "array",
      "description": "per-step Q1..Q4 answers + evidence",
      "minItems": 1
    },
    "issues": {
      "type": "array",
      "description": "{step, severity, fix}",
      "minItems": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation}",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}

example.code:
{
  "owner": "ruslan@faion.net",
  "last_touched": "2026-05-23T12:00:00Z",
  "template_version": "1.1.0",
